import React, { useContext, useEffect } from 'react';
import PlanetsContext from '../contexts/PlanetsContext';
import Loading from './Loading';

function Table() {
  const { loading, planets, getPlanets } = useContext(PlanetsContext);

  useEffect(() => {
    getPlanets();
    // eslint-disable-next-line
  }, []);

  const tableTitles = [
    'Name',
    'Rotation Period',
    'Orbital Period',
    'Diameter',
    'Climate',
    'Gravity',
    'Terrain',
    'Surface Water',
    'Population',
    'Films',
    'Created',
    'Edited',
    'URL',
  ];

  return (
    loading ? <Loading /> : (
      <table>
        <thead>
          {
            tableTitles.map((tiles, index) => (
              <th key={ index }>
                { tiles }
              </th>
            ))
          }
        </thead>
      </table>
    )
  // <p>Requisição concluida</p>
  );
}

export default Table;
